const body = $input.all()[0].json.body;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!body.tenantId || !uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid or missing tenantId');
}

return {
  tenantId: body.tenantId
};

// Aggregate all stats and compute compliance score
const fec = $node["05. Stats FEC"].json[0];
const facturx = $node["06. Stats Facturx"].json[0];
const ereporting = $node["07. Stats EReporting"].json[0];
const ediTva = $node["08. Stats EDI-TVA"].json[0];
const das2 = $node["09. Stats DAS2"].json[0];
const archives = $node["10. Stats Archives"].json[0];
const periodes = $node["11. Stats Periodes"].json[0];

// Calculate compliance scores
let fecScore = fec.total > 0 ? (fec.valides / fec.total) * 100 : 0;
let facturxScore = facturx.total > 0 ? (facturx.signes / facturx.total) * 100 : 0;
let ereportingScore = ereporting.total > 0 ? (ereporting.transmis / ereporting.total) * 100 : 0;
let ediTvaScore = ediTva.total > 0 ? (ediTva.transmises / ediTva.total) * 100 : 0;
let das2Score = das2.total > 0 ? (das2.transmises / das2.total) * 100 : 0;
let archivesScore = archives.expires === 0 ? 100 : 50;

const overallScore = Math.round((fecScore + facturxScore + ereportingScore + ediTvaScore + das2Score + archivesScore) / 6);

// Generate alerts
const alerts = [];
if (fecScore < 100) alerts.push({ level: 'warning', message: 'FEC: certains fichiers ne sont pas valides' });
if (facturxScore < 100) alerts.push({ level: 'warning', message: 'Factur-X: certaines factures ne sont pas signées' });
if (ereportingScore < 100) alerts.push({ level: 'warning', message: 'E-Reporting: données non transmises' });
if (ediTvaScore < 100) alerts.push({ level: 'warning', message: 'EDI-TVA: déclarations non transmises' });
if (das2Score < 100) alerts.push({ level: 'warning', message: 'DAS2: déclarations non transmises' });
if (archives.expires > 0) alerts.push({ level: 'error', message: `${archives.expires} archives ont dépassé leur date d'expiration` });
if (periodes.ouvertes === 0) alerts.push({ level: 'info', message: 'Aucune période comptable ouverte' });

return {
  fec: { total: fec.total, valides: fec.valides, score: Math.round(fecScore) },
  facturx: { total: facturx.total, signes: facturx.signes, score: Math.round(facturxScore) },
  ereporting: { total: ereporting.total, transmis: ereporting.transmis, score: Math.round(ereportingScore) },
  edi_tva: { total: ediTva.total, transmises: ediTva.transmises, score: Math.round(ediTvaScore) },
  das2: { total: das2.total, transmises: das2.transmises, score: Math.round(das2Score) },
  archives: { total: archives.total, expires: archives.expires, score: Math.round(archivesScore) },
  periodes: { total: periodes.total, ouvertes: periodes.ouvertes, fermees: periodes.fermees },
  overall_score: overallScore,
  alerts: alerts,
  timestamp: new Date().toISOString()
};

return {
  success: true,
  message: 'Dashboard loaded successfully',
  data: $input.all()[0].json
};
